def get_seed_from_user(user_data):
    """Генерирует уникальное число на основе данных пользователя и времени"""
    seed_str = f"{user_data.get('name', '')}_{user_data.get('gender', '')}_{user_data.get('question', '')}_{user_data.get('zodiac', '')}_{datetime.now().timestamp()}"
    return int(hashlib.md5(seed_str.encode()).hexdigest(), 16) % 10000

def generate_prediction(user_data):
    """Генерация уникального предсказания"""
    user_name = user_data.get('name', 'друг')
    user_gender = user_data.get('gender', 'other')
    user_question = user_data.get('question', '')
    
    logger.info(f"📝 Generating prediction for {user_name}")
    
    # Определяем категорию
    category = 'general'
    if user_question:
        q = user_question.lower()
        if any(w in q for w in ['работ', 'карьер', 'бизнес', 'денег', 'финанс']):
            category = 'career'
        elif any(w in q for w in ['любов', 'отношени', 'сердц', 'встреч', 'романт']):
            category = 'love'
        elif any(w in q for w in ['здоров', 'энерг', 'спорт', 'сон', 'устал']):
            category = 'health'
    
    # Генерируем уникальный seed на основе данных пользователя и времени
    seed = int(hashlib.md5(f"{user_name}_{user_gender}_{user_question}_{datetime.now().timestamp()}".encode()).hexdigest(), 16) % 10000
    random.seed(seed)
    
    templates = PREDICTION_TEMPLATES.get(category, PREDICTION_TEMPLATES['general'])
    template = random.choice(templates)
    
    # Сбрасываем seed
    random.seed()
    
    # Разные варианты обращения
    greetings = [
        f"✨ *{user_name}*, ",
        f"🌟 *{user_name}*, я вижу: ",
        f"🔮 *{user_name}*, слушай: ",
        f"💫 Дорогой(ая) *{user_name}*, ",
        f"💎 *{user_name}*, звёзды шепчут: ",
        f"⭐️ *{user_name}*, обрати внимание: ",
    ]
    
    # Используем время для дополнительной рандомизации
    greeting_index = int(datetime.now().timestamp() * 1000) % len(greetings)
    greeting = greetings[greeting_index]
    
    prediction = greeting + template
    return prediction

def generate_horoscope(zodiac_sign):
    """Генерация уникального гороскопа"""
    zodiac_lower = zodiac_sign.lower()
    
    logger.info(f"📝 Generating horoscope for {zodiac_sign}")
    
    # Используем время для рандомизации
    random.seed(int(datetime.now().timestamp() * 1000) % 100000)
    
    # Выбираем шаблон
    templates = HOROSCOPE_TEMPLATES.get(zodiac_lower, HOROSCOPE_TEMPLATES['овен'])
    horoscope = random.choice(templates)
    
    # Сбрасываем seed
    random.seed()
    
    return horoscope